// Title index for fuzzy matching
const CORE_TITLE_INDEX = {};
for (const [acronym, data] of Object.entries(CORE_RANKINGS)) {
  CORE_TITLE_INDEX[data.title.toLowerCase()] = { ...data, acronym };
}

/**
 * Look up CORE conference ranking by acronym or title
 * @param {string} query - Conference acronym or part of title
 * @returns {Object|null} Conference ranking info or null
 */
function lookupCOREConference(query) {
  if (!query || query.trim().length < 2) return null;
  const q = query.trim().toUpperCase();

  // 1. Exact acronym match
  if (CORE_RANKINGS[q]) {
    return { ...CORE_RANKINGS[q], acronym: q };
  }

  // 2. Case-insensitive key match
  for (const [acronym, data] of Object.entries(CORE_RANKINGS)) {
    if (acronym.toUpperCase() === q) {
      return { ...data, acronym };
    }
  }

  // 3. Word-boundary acronym in query (3+ chars to avoid false positives)
  for (const [acronym, data] of Object.entries(CORE_RANKINGS)) {
    if (acronym.length >= 3) {
      try {
        const escaped = acronym.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        const regex = new RegExp('\\b' + escaped + '\\b', 'i');
        if (regex.test(query)) {
          return { ...data, acronym };
        }
      } catch(e) { /* skip invalid regex */ }
    }
  }

  // 4. Full title match - require significant overlap
  const ql = query.trim().toLowerCase();
  if (ql.length >= 10) {
    for (const [title, data] of Object.entries(CORE_TITLE_INDEX)) {
      if (ql.includes(title) && title.length >= 20) return data;
    }
    for (const [title, data] of Object.entries(CORE_TITLE_INDEX)) {
      if (title.includes(ql) && ql.length >= 15) return data;
    }
  }

  return null;
}
